      "keystrokes": "cd /app; gcc -static -o reversed mystery.c -lm && ./reversed 2>/tmp/stderr.txt; cmp /tmp/original.ppm image.ppm && echo EXACT_MATCH || echo MISMATCH; md5sum image.ppm /tmp/original.ppm; cat /tmp/stderr.txt; echo -n 'source gzip bytes: '; cat mystery.c | gzip | wc -c
